section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/decomposition-django.json",
  "type": "object",
  "title": "Decomposition: Django Monolith to Bounded Apps",
  "required": [
    "boundary_id",
    "apps",
    "dependency_edges",
    "forbidden_edges",
    "owner_map",
    "migration_plan"
  ],
  "additionalProperties": false,
  "properties": {
    "boundary_id": {
      "type": "string",
      "minLength": 1,
      "description": "Unique boundary identifier."
    },
    "apps": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "App names in the decomposed graph."
    },
    "dependency_edges": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Allowed edges in the form 'src->dst'."
    },
    "forbidden_edges": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Edges import-linter forbids."
    },
    "owner_map": {
      "type": "object",
      "description": "{app_name: team_name}."
    },
    "migration_plan": {
      "type": "array",
      "items": {
        "type": "object"
      },
      "description": "Ordered model moves with PR identifiers."
    }
  }
}
